import{_ as e,c as o,o as a,a1 as s}from"./chunks/framework.DDNAyvCW.js";const n="/assets/host_bastion_create.jOSwBR9t.png",p=JSON.parse('{"title":"Add a Bastion Host","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/add-bastion.md","filePath":"docs/hosts/add-bastion.md"}'),i={name:"docs/hosts/add-bastion.md"};function r(d,t,l,h,c,g){return a(),o("div",null,t[0]||(t[0]=[s('<h1 id="add-a-bastion-host" tabindex="-1">Add a Bastion Host <a class="header-anchor" href="#add-a-bastion-host" aria-label="Permalink to &quot;Add a Bastion Host&quot;">â€‹</a></h1><p>Add a bastion host to Chaterm to access enterprise-level assets that are synchronized from a centralized bastion (jump server) system.</p><div class="info custom-block"><p class="custom-block-title">What is a bastion host?</p><p>A bastion host (also called a jump server) is a hardened gateway server that sits between your local machine and the internal servers you need to manage. Instead of connecting to each server directly, you connect through the bastion host, which enforces access controls, auditing, and security policies. Organizations use bastion hosts to centrally manage who can access which servers and to maintain a full audit trail of all sessions.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">â€‹</a></h2><p>Before adding a bastion host, make sure you have:</p><ul><li><strong>Chaterm installed</strong> and running. See <a href="/docs/start/downloads/">Downloads</a> if you have not installed it yet.</li><li><strong>Bastion host credentials</strong> -- typically a combination of an SSH key and a password, as required by your organization&#39;s bastion system.</li><li><strong>Connection address</strong> -- the IP address or domain name of the bastion host, along with the SSH port.</li><li><strong>Access permissions</strong> granted by your organization&#39;s administrator to connect through the bastion.</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">â€‹</a></h2><p><img src="'+n+'" alt=""></p><ol><li>Open the <strong>Host Management</strong> page from the left sidebar.</li><li>Click <strong>Add Host</strong> in the top-right corner of the Host Management page.</li><li>In the <strong>Add Host</strong> sidebar that opens, set <strong>Device type</strong> to <strong>Server / Bastion</strong>.</li><li>Fill in the remaining configuration fields described in the table below.</li><li>Click <strong>Create</strong> to save the bastion host.</li></ol><h2 id="configuration-fields" tabindex="-1">Configuration Fields <a class="header-anchor" href="#configuration-fields" aria-label="Permalink to &quot;Configuration Fields&quot;">â€‹</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>Device Type</strong></td><td>Select <strong>Server / Bastion</strong> to indicate this is a bastion host resource.</td><td>Yes</td></tr><tr><td><strong>Connection IP/URL</strong></td><td>The IP address or domain name of the bastion host (e.g. <code>bastion.corp.example.com</code>).</td><td>Yes</td></tr><tr><td><strong>Port</strong></td><td>The SSH service port on the bastion host. Defaults to <code>22</code>.</td><td>Yes</td></tr><tr><td><strong>Username</strong></td><td>The SSH login username assigned to you on the bastion system.</td><td>Yes</td></tr><tr><td><strong>Key</strong></td><td>Select the SSH authentication key required by the bastion host. Keys can be managed in <a href="/docs/manage/keys/">Key Management</a>.</td><td>Yes</td></tr><tr><td><strong>Password</strong></td><td>The authentication password required by the bastion host. Some bastion systems require both a key and a password for two-factor authentication.</td><td>Yes</td></tr><tr><td><strong>SSH Proxy</strong></td><td>If the bastion host itself must be reached through an intermediate proxy server, configure the proxy details here. Leave empty for direct connections.</td><td>No</td></tr><tr><td><strong>Alias</strong></td><td>A friendly display name to identify this bastion host in the host list (e.g. <code>Production Bastion</code>).</td><td>Yes</td></tr><tr><td><strong>Group</strong></td><td>Assign the bastion host to a group for organization (e.g. <code>bastion</code>, <code>production</code>). You can select an existing group or type a new name.</td><td>No</td></tr></tbody></table><h2 id="sync-bastion-assets" tabindex="-1">Sync Bastion Assets <a class="header-anchor" href="#sync-bastion-assets" aria-label="Permalink to &quot;Sync Bastion Assets&quot;">â€‹</a></h2><p>After adding a bastion host, Chaterm displays it on the bastion resource page along with a list of the internal assets available through it.</p><p>To update the asset list with the latest information from the bastion system:</p><ol><li>Navigate to the <strong>Bastion Resources</strong> tab in the workspace.</li><li>Locate the bastion host entry you want to refresh.</li><li>Click the <strong>Refresh</strong> button next to the bastion host to manually sync the latest asset data.</li></ol><p>Once synced, the internal assets appear in the list just like personal hosts. Click any asset to establish an SSH connection. You can also right-click an asset to add it to favorites, attach notes, or assign it to a custom group.</p><h2 id="custom-group-management" tabindex="-1">Custom Group Management <a class="header-anchor" href="#custom-group-management" aria-label="Permalink to &quot;Custom Group Management&quot;">â€‹</a></h2><p>You can create custom groups to organize bastion assets in a way that makes sense for your team:</p><ol><li>In the workspace, select the <strong>Bastion Resources</strong> tab.</li><li>Click the <strong>Custom Group</strong> button in the upper-right corner.</li><li>Fill in the group details: <ul><li><strong>Group Name</strong> -- a short, descriptive name (e.g. <code>Web Servers</code>, <code>Database Tier</code>).</li><li><strong>Group Description</strong> -- an optional note explaining what this group contains.</li></ul></li><li>Click <strong>Save</strong> to create the group.</li></ol><p>To edit or delete an existing custom group, right-click the group on the bastion resource page and choose the appropriate action from the context menu.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">â€‹</a></h2><ul><li><a href="/docs/manage/keys/">Key Management</a> -- import and manage SSH keys used for bastion authentication.</li><li><a href="/docs/hosts/connect">Connect to a Host</a> -- learn about terminal features available when you connect to a bastion asset.</li><li><a href="/docs/hosts/edit-clone-delete">Edit, Clone &amp; Delete</a> -- modify or remove bastion host entries.</li></ul>',22)]))}const m=e(i,[["render",r]]);export{p as __pageData,m as default};
